import{_ as g,z as w,j as y,k as q,a7 as k,a as r,b as e,G as f,f as u,n as x,o as l}from"./index.1b69dad7.js";const T={class:"help-container"},A={key:0,class:"toc"},S={key:1,class:"help-footer"},I={__name:"pixelPower",setup(E){const h=w(),c=y(h.query.autoScroll==="true");let s=null;const n=t=>{var d;if(!c.value&&t.target.tagName==="A"&&((d=t.target.getAttribute("href"))==null?void 0:d.startsWith("#"))){t.preventDefault();const o=t.target.getAttribute("href").slice(1),a=document.getElementById(o);a&&a.scrollIntoView({behavior:"smooth",block:"start"})}},p=()=>{const t=document.querySelector(".help-page");if(!t)return;let d=1,o=1,a=0;const v=360,i=()=>{const m=t.scrollHeight-t.clientHeight,b=t.scrollTop;if(a>0){a--,s=requestAnimationFrame(i);return}d===1?(t.scrollTop+=o,b>=m-10&&(a=v,d=-1,o=100)):(t.scrollTop-=o,b<=10&&(a=v,d=1,o=1)),s=requestAnimationFrame(i)};s=requestAnimationFrame(i)};return q(()=>{document.addEventListener("click",n),c.value&&setTimeout(p,1e3)}),k(()=>{document.removeEventListener("click",n),s&&cancelAnimationFrame(s)}),(t,d)=>(l(),r("div",{class:x(["help-page",{"auto-scroll-mode":c.value}])},[e("div",T,[d[2]||(d[2]=e("header",{id:"top",class:"help-header"},[e("h1",{class:"crt-text-green"},"\u{1F3A8} PIXEL POWER: AI ART COLLAB"),e("p",{class:"subtitle"},"Create Amazing AI Art Together!")],-1)),c.value?u("",!0):(l(),r("nav",A,[...d[0]||(d[0]=[f('<h2 class="crt-text-yellow" data-v-df5d15bc>Quick Navigation</h2><ul data-v-df5d15bc><li data-v-df5d15bc><a href="#basics" data-v-df5d15bc>Game Basics</a></li><li data-v-df5d15bc><a href="#commands" data-v-df5d15bc>How to Play</a></li><li data-v-df5d15bc><a href="#limits" data-v-df5d15bc>Submission Limits</a></li><li data-v-df5d15bc><a href="#dictionary" data-v-df5d15bc>Word Rules</a></li><li data-v-df5d15bc><a href="#scoring" data-v-df5d15bc>Scrabble Scoring</a></li><li data-v-df5d15bc><a href="#display" data-v-df5d15bc>Word Display</a></li><li data-v-df5d15bc><a href="#generation" data-v-df5d15bc>Image Generation</a></li><li data-v-df5d15bc><a href="#rewards" data-v-df5d15bc>Rewards</a></li><li data-v-df5d15bc><a href="#tips" data-v-df5d15bc>Pro Tips</a></li></ul>',2)])])),d[3]||(d[3]=f('<section id="basics" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F4D6} Game Basics</h2><div class="content-block" data-v-df5d15bc><h3 data-v-df5d15bc>What is Pixel Power?</h3><p data-v-df5d15bc>Pixel Power is a collaborative AI art creation game where the Twitch community works together to generate unique images! Submit words in chat through 12 rounds (3 words per round = 36 total), and the AI creates a stunning video game-style artwork based on ALL submitted words combined!</p><h3 data-v-df5d15bc>How It Works</h3><ol data-v-df5d15bc><li data-v-df5d15bc><strong data-v-df5d15bc>Round System:</strong> Game has 12 rounds, each accepting 3 words starting with a specific letter</li><li data-v-df5d15bc><strong data-v-df5d15bc>Submit Words:</strong> When each round starts, the starting letter is displayed on stream.<br data-v-df5d15bc> Type <code class="crt-text-yellow" data-v-df5d15bc>!art [word-with-matching-first-letter]</code> in chat</li><li data-v-df5d15bc><strong data-v-df5d15bc>Collection Builds:</strong> 3 words per round x 12 rounds = 36 words across all rounds</li><li data-v-df5d15bc><strong data-v-df5d15bc>Image Generated:</strong> AI creates art when 36 words reached every 4-6 hours<br data-v-df5d15bc>(or in the very unlikely event 24 hours pass without collecting enough words)</li><li data-v-df5d15bc><strong data-v-df5d15bc>Earn Rewards:</strong> Get zCubes based on a mod&#39;d Scrabble score \xD7 13 multiplier!</li></ol><div class="pro-tip" data-v-df5d15bc><strong data-v-df5d15bc>\u{1F4A1} Cool Feature:</strong> each round will end after 3 words are submitted. There is a 5-10 min cooldown before the next round. This prevents spam and gives everyone time to participate across different time zones! </div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="commands" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F4AC} How to Play</h2><div class="command-list" data-v-df5d15bc><div class="command-item" data-v-df5d15bc><h3 data-v-df5d15bc><code class="crt-text-yellow" data-v-df5d15bc>!art [word]</code></h3><p data-v-df5d15bc>Submit a single dictionary word to the collection</p><p data-v-df5d15bc><strong data-v-df5d15bc>Examples:</strong></p><ul data-v-df5d15bc><li data-v-df5d15bc><code data-v-df5d15bc>!art dragon</code> - Submit the word &quot;dragon&quot;</li><li data-v-df5d15bc><code data-v-df5d15bc>!art sword</code> - Submit the word &quot;sword&quot;</li><li data-v-df5d15bc><code data-v-df5d15bc>!art crystal</code> - Submit the word &quot;crystal&quot;</li></ul><div class="note" data-v-df5d15bc><strong data-v-df5d15bc>\u26A0\uFE0F Important:</strong> Only ONE word at a time! Words like &quot;fire dragon&quot; won&#39;t work. Submit them separately: <code data-v-df5d15bc>!art fire</code> then <code data-v-df5d15bc>!art dragon</code></div></div><div class="command-item" data-v-df5d15bc><h3 data-v-df5d15bc>What Happens After Submission?</h3><ol data-v-df5d15bc><li data-v-df5d15bc><strong data-v-df5d15bc>Validation:</strong> Word is checked against dictionary API</li><li data-v-df5d15bc><strong data-v-df5d15bc>Scoring:</strong> Scrabble score is calculated (see Scoring section)</li><li data-v-df5d15bc><strong data-v-df5d15bc>Collection Update:</strong>per round countdown (e.g. 3 words left)</li></ol></div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="limits" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u23F1\uFE0F Submission Limits</h2><div class="content-block" data-v-df5d15bc><h3 data-v-df5d15bc>Per-User Limits</h3><p data-v-df5d15bc>To keep things fair and give everyone a chance to contribute:</p><div class="limit-box daily" data-v-df5d15bc><h4 data-v-df5d15bc>\u{1F4C5} Daily Limit</h4><ul data-v-df5d15bc><li data-v-df5d15bc><strong data-v-df5d15bc>12 words per day</strong> per user</li><li data-v-df5d15bc>Reset when the next picture is created <strong data-v-df5d15bc>after midnight EST (UTC-5) or in summer EDT (UTC-4)</strong></li><li data-v-df5d15bc>Shared across all users (everyone resets together)</li></ul><div class="example" data-v-df5d15bc><strong data-v-df5d15bc>Example:</strong><ul data-v-df5d15bc><li data-v-df5d15bc>If the session started (in winter) at 5:01 UTC</li><li data-v-df5d15bc>You can submit up to 12 words total until 5:00 UTC</li><li data-v-df5d15bc>At 5:00 UTC, everyone&#39;s daily limit resets to 12</li></ul></div></div><h3 data-v-df5d15bc>What Happens When You Hit a Limit?</h3><div class="limit-messages" data-v-df5d15bc><div class="message-box" data-v-df5d15bc><code class="crt-text-red" data-v-df5d15bc>\u{1F504} @username You&#39;ve added your word this round! Wait for the next round (check overlay for cooldown).</code><p data-v-df5d15bc>each user may submit 1 word per round, please wait for the next round</p></div><div class="message-box" data-v-df5d15bc><code class="crt-text-red" data-v-df5d15bc>\u{1F3A8} @username \u{1F7E8} YELLOW card! You&#39;ve hit your daily limit. Half points on your next word tomorrow \u{1F319}</code><p data-v-df5d15bc>each successful submission will tell you how many words you have left. when you have used all 12, your avatar will also display on stream beside a lock symbol as a reminder with a timer counting down till &quot;tomorrow&quot; (in EDT/EST) then it will say &quot;reset after round 12&quot;</p><p data-v-df5d15bc>reset happens after a new picture is made every &quot;new day&quot; (relative to the streamer&#39;s timezone)</p></div></div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="dictionary" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F4DA} Word Rules</h2><div class="content-block" data-v-df5d15bc><h3 data-v-df5d15bc>Valid Words</h3><p data-v-df5d15bc>All words are validated using a real English dictionary API. To be accepted, your word must:</p><ul data-v-df5d15bc><li data-v-df5d15bc>\u2705 Be a real English word</li><li data-v-df5d15bc>\u2705 Be found in the dictionary</li><li data-v-df5d15bc>\u2705 Be a single word (some exceptions apply like &quot;black hole&quot;)</li><li data-v-df5d15bc>\u2705 Be spelled correctly</li></ul><h3 data-v-df5d15bc>Invalid Words</h3><ul data-v-df5d15bc><li data-v-df5d15bc>\u274C Multiple words: &quot;fire dragon&quot; \u2192 Use separately</li><li data-v-df5d15bc>\u274C Misspellings: &quot;dragn&quot; \u2192 Won&#39;t be accepted</li><li data-v-df5d15bc>\u274C Made-up words: &quot;flibbertigibbet&quot; \u2192 Depends on dictionary!</li><li data-v-df5d15bc>\u274C Numbers/symbols: &quot;dr4gon&quot; \u2192 Letters only</li></ul><div class="pro-tip" data-v-df5d15bc><strong data-v-df5d15bc>\u{1F4A1} Fun Fact:</strong> The dictionary includes some quirky but real words! Try &quot;defenestration&quot; (throwing someone out a window) or &quot;petrichor&quot; (the smell of rain on dry earth). </div><h3 data-v-df5d15bc>What Happens if Word is Invalid?</h3><div class="message-box" data-v-df5d15bc><code class="crt-text-red" data-v-df5d15bc>\u26A0\uFE0F @username \u{1F7E8} 1/3 fails: that is not a dictionary word</code><p data-v-df5d15bc>after three invalid words, a \u{1F7E8} yellow card is issued that will give half points on your next submission.</p><p data-v-df5d15bc>any &quot;proper&quot; word will reset the counter</p></div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="scoring" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F3AF} Scrabble Scoring</h2><div class="content-block" data-v-df5d15bc><h3 data-v-df5d15bc>How Scoring Works</h3><p data-v-df5d15bc>Each word earns a Scrabble score based on letter values, multiplied by 13! Higher scores mean more zCubes. This rewards creative vocabulary!</p><div class="score-table" data-v-df5d15bc><h4 data-v-df5d15bc>Letter Values</h4><table data-v-df5d15bc><tr data-v-df5d15bc><th data-v-df5d15bc>Points</th><th data-v-df5d15bc>Letters</th></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>0</td><td data-v-df5d15bc>X, Z</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>1</td><td data-v-df5d15bc>A, E, I, O, U, L, N, S, T, R, Q</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>2</td><td data-v-df5d15bc>D, G</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>3</td><td data-v-df5d15bc>B, C, M, P</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>4</td><td data-v-df5d15bc>F, H, V, W, Y</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>5</td><td data-v-df5d15bc>K</td></tr><tr data-v-df5d15bc><td class="score" data-v-df5d15bc>8</td><td data-v-df5d15bc>J</td></tr></table></div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="generation" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F3A8} Image Generation</h2><div class="content-block" data-v-df5d15bc><h3 data-v-df5d15bc>When Does Generation Happen?</h3><p data-v-df5d15bc>AI image generation is triggered by ONE of these conditions:</p><div class="trigger-conditions" data-v-df5d15bc><div class="trigger" data-v-df5d15bc><h4 class="crt-text-yellow" data-v-df5d15bc>\u{1F3AF} 36 Words Collected</h4><p data-v-df5d15bc>When the 36th word is submitted, image generation starts immediately!</p></div><div class="trigger" data-v-df5d15bc><h4 class="crt-text-cyan" data-v-df5d15bc>\u23F0 24-Hour Timer Expires</h4><p data-v-df5d15bc>If 36 words aren&#39;t reached in 24 hours, the AI generates from whatever words are available (even if just 5 or 10 words!).</p></div></div><h3 data-v-df5d15bc>The Generation Process</h3><ol data-v-df5d15bc><li data-v-df5d15bc><strong data-v-df5d15bc>Collection Completes:</strong> 36 words OR timer expires</li><li data-v-df5d15bc><strong data-v-df5d15bc>Prompt Building:</strong> All words combined into AI prompt</li><li data-v-df5d15bc><strong data-v-df5d15bc>AI Generation:</strong> Nano Banana creates the image</li><li data-v-df5d15bc><strong data-v-df5d15bc>Style Applied:</strong> &quot;video game art, concept art, cinematic lighting&quot;</li><li data-v-df5d15bc><strong data-v-df5d15bc>Display:</strong> Generated image appears in carousel</li><li data-v-df5d15bc><strong data-v-df5d15bc>Reset:</strong> New session begins with 0/36 words!</li></ol><h3 data-v-df5d15bc>What Makes the Art Unique?</h3><p data-v-df5d15bc>The AI combines ALL submitted words into a single coherent image with these characteristics:</p><ul data-v-df5d15bc><li data-v-df5d15bc>\u{1F3AE} Video game art style</li><li data-v-df5d15bc>\u2728 Cinematic lighting and atmosphere</li><li data-v-df5d15bc>\u{1F5BC}\uFE0F Ultra-detailed, intricate elements</li><li data-v-df5d15bc>\u{1F3AD} Dramatic composition</li><li data-v-df5d15bc>\u{1F308} Rich colors and depth of field</li></ul><div class="example" data-v-df5d15bc><strong data-v-df5d15bc>Example Prompt:</strong><p data-v-df5d15bc>If words submitted are: dragon, sword, crystal, fire, castle...</p><p class="crt-text-cyan" data-v-df5d15bc>&quot;dragon, sword, crystal, fire, castle, video game art, concept art, game asset, rendered in Unreal Engine, cinematic lighting, dramatic atmosphere, masterpiece, best quality, ultra detailed&quot;</p></div><div class="pro-tip" data-v-df5d15bc><strong data-v-df5d15bc>\u{1F4A1} Collaboration Tip:</strong> Coordinate with other viewers! Plan themed collections like &quot;underwater adventure&quot; or &quot;space exploration&quot; for cohesive, amazing results! </div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section><section id="tips" class="help-section" data-v-df5d15bc><h2 class="crt-text-green" data-v-df5d15bc>\u{1F3C6} Pro Tips &amp; Strategy</h2><div class="tips-grid" data-v-df5d15bc><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u{1F3AD} Theme Your Words</h3><p data-v-df5d15bc>Coordinate with chat! Themed collections create better, more cohesive AI art.</p></div><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u{1F31F} Be Creative</h3><p data-v-df5d15bc>Don&#39;t just use common words! &quot;ETHEREAL&quot; or &quot;LUMINOUS&quot; make for better art than &quot;THING&quot; or &quot;STUFF&quot;.</p></div><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u{1F4DA} Expand Your Vocabulary</h3><p data-v-df5d15bc>Every word is shown with its definition. Learn new words while playing!</p></div><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u{1F91D} Collaborate</h3><p data-v-df5d15bc>Discuss in chat! Build on others&#39; words to create a cohesive concept.</p></div><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u{1F3A8} Visual Thinking</h3><p data-v-df5d15bc>Think about how words will look combined. &quot;DRAGON&quot; + &quot;FIRE&quot; + &quot;MOUNTAIN&quot; = Epic scene!</p></div><div class="tip-card" data-v-df5d15bc><h3 data-v-df5d15bc>\u26A1 Be Quick but Thoughtful</h3><p data-v-df5d15bc>Don&#39;t waste submissions on low-value, common words when you have limited tries!</p></div></div><a href="#top" class="back-to-top" data-v-df5d15bc>\u2191 Back to Top</a></section>',7)),c.value?u("",!0):(l(),r("footer",S,[...d[1]||(d[1]=[e("p",{class:"crt-text-green"},"Ready to create amazing art together? Jump in chat and type !art [word]! \u{1F3A8}\u2728",-1),e("p",null,[e("a",{href:"/art",class:"back-link"},"\u2190 Back to Pixel Power")],-1)])]))])],2))}},B=g(I,[["__scopeId","data-v-df5d15bc"]]);export{B as default};
